insert into knowledge_nodes (id, project_id, node_key, label, category, sub_label, facts, talkpoint, description, sort_order) values
  ('ffb6ef02-0d5e-5095-b283-82b702c86583','00000000-0000-0000-0000-00000000b003','vgp','Vinhomes Green Paradise','project','KĐT du lịch lấn biển Cần Giờ — 2.870 ha','[{"key":"Tên pháp lý","value":"Khu đô thị du lịch lấn biển Cần Giờ"},{"key":"Tên cũ","value":"Saigon Sunbay (thời Saigontourist)"},{"key":"Vị trí","value":"Xã Long Hòa + TT Cần Thạnh (cũ) → nay xã Cần Giờ, TP.HCM"},{"key":"Quy mô","value":"2.870 ha — lấn biển ~1.357 ha, ~13 km bờ biển"},{"key":"Tổng vốn","value":"217.054 tỷ đồng (~9 tỷ USD; truyền thông gần đây ~10 tỷ USD)"},{"key":"Dân số quy hoạch","value":"Tối đa ~230.000 người"},{"key":"Khách du lịch mục tiêu","value":"8–9 triệu lượt/năm (riêng dự án)"},{"key":"Khởi công","value":"19/4/2025 — chuỗi công trình 50 năm Thống nhất"},{"key":"Cách trung tâm","value":"~50 km; 3 mặt giáp biển, 1 mặt giáp rừng ngập mặn"}]'::jsonb,'"Đây là quỹ đất mặt biển DUY NHẤT của TP.HCM — thành phố 10 triệu dân chưa từng có đô thị biển. Cái Vinhomes bán không phải căn nhà, mà là vị thế độc quyền địa lý không thể tái tạo."','✅ ĐÃ XÁC MINH (QĐ 826/QĐ-TTg, QĐ 340/QĐ-UBND, VnExpress, Tuổi Trẻ, cổng TP.HCM) Siêu dự án lấn biển duy nhất của TP.HCM, san nền ~906 ha cao độ >2,9m (Hòn Dấu). 70% diện tích là cây xanh + mặt nước theo quy hoạch.',0),
  ('139d27aa-2c55-5ca4-b385-08cdb786f55c','00000000-0000-0000-0000-00000000b003','pk-a','Phân khu A — The Haven Bay (Vịnh Tiên)','project',null,'[{"key":"Diện tích","value":"~771 ha (QĐ 340) / 953 ha (QĐ 3800 cũ)"},{"key":"Chức năng","value":"Cửa ngõ — giải trí, nghỉ dưỡng"},{"key":"Điểm nhấn","value":"VinWonders 122 ha + 2 sân golf 18 lỗ"},{"key":"Vai trò bán hàng","value":"Phân khu ra mắt/mở bán đầu tiên"},{"key":"Thi công (4/2026)","value":"Shophouse xây lên tầng 2, nhiều căn dự kiến xong trong 2026"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN — diện tích theo văn bản quy hoạch ✅ ĐÃ XÁC MINH; tên thương mại "The Haven Bay/Vịnh Tiên" từ truyền thông CĐT.',1),
  ('2e4e10ec-2646-5a2d-9430-3a7f19827383','00000000-0000-0000-0000-00000000b003','pk-b','Phân khu B — The Green Bay (Vịnh Ngọc)','project',null,'[{"key":"Diện tích","value":"~587 ha"},{"key":"Chức năng","value":"An cư — y tế, giáo dục"},{"key":"Điểm nhấn","value":"Nhà hát Sóng Xanh (~5.000 chỗ)"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN — số liệu quy hoạch xác minh; tên thương mại từ CĐT/môi giới.',2),
  ('fcc30931-be45-5076-9bbb-3985d32d3d1d','00000000-0000-0000-0000-00000000b003','pk-c','Phân khu C — The Paradise (Mũi Hải Đăng)','project',null,'[{"key":"Diện tích","value":"~303–318 ha"},{"key":"Chức năng","value":"Tài chính — thương mại"},{"key":"Điểm nhấn","value":"Tháp 108 tầng (~550m, chưa khởi công)"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN — phân khu "Danh Vọng" định vị CBD biển; giá trị phụ thuộc hoàn toàn vào việc tháp 108 tầng có triển khai đúng quảng bá.',3),
  ('e6461f27-cfbc-5cc0-9204-d58964f46eba','00000000-0000-0000-0000-00000000b003','pk-de','Phân khu D–E — The Grand Island','project',null,'[{"key":"Diện tích","value":"D ~450–480 ha + E ~458 ha (mặt nước/cây xanh)"},{"key":"Chức năng","value":"Nghỉ dưỡng cao cấp — đảo"},{"key":"Định vị","value":"Sản phẩm giới hạn, giá trần của dự án"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN',4),
  ('e4d3608b-d8f9-5d17-85e0-e90d022f52b7','00000000-0000-0000-0000-00000000b003','tien-do','Tiến độ thi công','project',null,'[{"key":"Khởi công","value":"19/4/2025"},{"key":"San lấp (10/2025)","value":"~110/122 triệu m³ cát (~50% khối lượng) — gấp ~50 lần Vinhomes Central Park"},{"key":"Mốc 1 năm (4/2026)","value":"San lấp phần lớn ~1.350 ha lấn biển; đại lộ rộng tới 120m; hệ thống thoát nước"},{"key":"Sản phẩm","value":"Shophouse Vịnh Tiên lên tầng 2; cặp biệt thự đầu tiên đã cất nóc"},{"key":"Lộ trình","value":"GĐ1 2025–2028 · GĐ2 2028–2031"},{"key":"Bàn giao thấp tầng","value":"Dự kiến cuối 2027 – đầu 2028"}]'::jsonb,'"Khác mọi dự án biển từng thất hứa: cái này khách có thể tự chạy xe xuống xem — 1.350 ha đất mới đã nằm trên biển, shophouse đã lên tầng 2. Đất đã có thật, câu hỏi chỉ còn là giá."','✅ ĐÃ XÁC MINH (báo chí ghi nhận hiện trường) Tốc độ thi công là luận điểm mạnh nhất chống lại lo ngại "quy hoạch trên giấy" — dự án đã hiện hữu vật lý chỉ sau 1 năm.',5),
  ('f447ffbd-edfb-5db3-b29f-2b85ead05ed5','00000000-0000-0000-0000-00000000b003','gia-rumor','Giá & CSBH (rumor)','project','⚠ TIN ĐỒN — Vinhomes chưa công bố giá chính thức','[{"key":"Liền kề (rumor)","value":"~99–134 triệu/m² · từ ~10–13 tỷ/căn (75–125m²)"},{"key":"Song lập (rumor)","value":"Từ ~18 tỷ/căn"},{"key":"Đơn lập (rumor)","value":"Từ ~30 tỷ/căn"},{"key":"Shophouse (rumor)","value":"Từ ~25 tỷ/căn"},{"key":"Căn hộ (ước)","value":"~70–90 triệu/m²"},{"key":"Booking","value":"100–200 triệu/căn — hoàn lại 100%"},{"key":"CSBH (đồn)","value":"HTLS 0% tới ~36 tháng · CK thanh toán sớm ~7,5%"},{"key":"Cam kết thuê (đồn)","value":"Shophouse 6%/năm trong 5 năm"}]'::jsonb,'"Quy tắc duy nhất: giá chỉ có thật khi nằm trong bảng giá sự kiện mở bán của Vinhomes. Mọi bảng giá đang chuyền tay là môi giới tự tổng hợp — dùng để tham khảo khung, không dùng để xuống tiền."','⚠ TIN ĐỒN / CHƯA XÁC MINH Toàn bộ con số từ website môi giới (vinhome.land, vinhomesgreensparadise.vn, adongland.vn…) — chính các trang này tự ghi "giá dự kiến/rumor". Bài VnExpress ra mắt Vịnh Tiên không nêu giá. Đây là phát hiện quan trọng: thị trường đang định giá thay CĐT.',6),
  ('8020987c-8d9d-5dbd-9c4f-6b3126bfb295','00000000-0000-0000-0000-00000000b003','vinhomes-vg','Vinhomes / Vingroup','developer',null,'[{"key":"Thương hiệu phát triển","value":"Vinhomes (VHM)"},{"key":"Vingroup mua cổ phần","value":"~13.272 tỷ đồng (giai đoạn 2015–2016)"},{"key":"Tỷ lệ sở hữu CTC","value":"97,15%"},{"key":"Năng lực tham chiếu","value":"Ocean Park 1-2-3, Grand Park, Royal Island"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (Znews, Tuổi Trẻ, cổng thông tin TP.HCM) Cam kết thương hiệu đáng chú ý: bảo hành nền móng trọn đời cho công trình trên đất lấn biển — câu trả lời trực diện cho lo ngại địa chất.',7),
  ('147a1a90-03d3-53c8-8843-717d498d2eca','00000000-0000-0000-0000-00000000b003','ctc','CTC Corp (pháp nhân)','developer',null,'[{"key":"Tên đầy đủ","value":"CTCP Đô thị Du lịch Cần Giờ"},{"key":"Thành lập","value":"21/9/2004"},{"key":"Vốn điều lệ","value":"525,7 tỷ đồng"},{"key":"Cổ đông lịch sử","value":"Saigontourist + Văn phòng Thành ủy TP.HCM"},{"key":"Hiện tại","value":"Vingroup sở hữu 97,15%"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Mọi văn bản pháp lý dự án cấp cho pháp nhân CTC — khách tra cứu thấy tên "Đô thị Du lịch Cần Giờ" thay vì "Vinhomes" là bình thường.',8),
  ('e07b57dd-0253-5daa-9f86-eafd6e92412d','00000000-0000-0000-0000-00000000b003','lich-su','Lịch sử dự án (2004 → 2025)','developer',null,'[{"key":"2004","value":"CTC thành lập — dự án Saigon Sunbay 600 ha"},{"key":"2007–2014","value":"Đình trệ kéo dài (năng lực tài chính chủ cũ)"},{"key":"2015–2016","value":"Vingroup mua ~13.272 tỷ → nắm 97,15%"},{"key":"12/6/2020","value":"QĐ 826/QĐ-TTg: mở rộng 600 ha → 2.870 ha"},{"key":"24/1/2025","value":"Duyệt QH 1/500 (QĐ 340)"},{"key":"19/4/2025","value":"Khởi công — sau 21 năm thai nghén"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Mẫu hình lặp lại của Vinhomes Saigon Park: dự án "đắp chiếu" hàng chục năm + Vingroup vào + pháp lý chạy thần tốc 2025–2026.',9),
  ('15a5be9b-157e-5569-a7bf-0ead2cf7bf34','00000000-0000-0000-0000-00000000b003','qd-826','QĐ 826/QĐ-TTg (12/6/2020)','legal',null,'[{"key":"Cấp ban hành","value":"Phó Thủ tướng Trịnh Đình Dũng ký"},{"key":"Nội dung","value":"Điều chỉnh chủ trương: mở rộng 600 → 2.870 ha"},{"key":"Cơ cấu vốn","value":"217.054 tỷ — vốn CSH 15% / vốn vay 85%"},{"key":"Tiến độ cho phép","value":"11 năm"},{"key":"Thời hạn dự án","value":"50 năm"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (xác nhận bởi cổng thông tin TP.HCM) Văn bản gốc quyết định quy mô siêu dự án — mọi tranh luận pháp lý đều quay về quyết định này.',10),
  ('ca1dd36c-c54c-523e-98c6-a777ecbb766c','00000000-0000-0000-0000-00000000b003','qd-340','QH 1/500 — QĐ 340 (24/1/2025)','legal',null,'[{"key":"Văn bản","value":"QĐ 340/QĐ-UBND TP.HCM, 24/1/2025"},{"key":"Nội dung","value":"Quy hoạch chi tiết 1/500 — chia 4 phân khu A, B, C, D-E"},{"key":"Nền tảng trước đó","value":"QĐ 3800/QĐ-UBND (5/9/2018): quy hoạch phân khu 1/5000"},{"key":"Ý nghĩa","value":"\"Hộ chiếu pháp lý\" để cấp phép, thi công, thẩm định ngân hàng"}]'::jsonb,'"1/500 duyệt tháng 1, khởi công tháng 4 cùng năm — chuỗi pháp lý liền mạch là thứ phân biệt dự án này với 20 năm tin đồn Cần Giờ trước đó."','✅ ĐÃ XÁC MINH',11),
  ('4eb09b03-6a72-5e28-a3bf-8fb47b4337aa','00000000-0000-0000-0000-00000000b003','dtm','ĐTM — phê duyệt 21/2/2025','legal',null,'[{"key":"Phê duyệt","value":"Bộ TN&MT — 21/2/2025"},{"key":"Sau đó","value":"Có điều chỉnh ĐTM được đăng tham vấn"},{"key":"Điều kiện kèm theo","value":"Yêu cầu TIẾP TỤC nghiên cứu tác động xói lở, bồi tụ, dòng chảy"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN — quyết định phê duyệt là thật; nhưng chính văn bản thừa nhận rủi ro môi trường chưa đóng hồ sơ. Đây là node trung tâm của mọi câu hỏi môi trường: ĐTM đã có, song kèm điều kiện giám sát tiếp — tư vấn trung thực cần nói cả hai vế.',12),
  ('30a72dac-3745-52cf-b4ea-a7bcc933450f','00000000-0000-0000-0000-00000000b003','so-huu','Hình thức sở hữu','legal',null,'[{"key":"Người Việt Nam","value":"Sổ hồng LÂU DÀI"},{"key":"Người nước ngoài","value":"50 năm"},{"key":"Quy trình mua","value":"Booking (hoàn 100%) → Thỏa thuận đặt cọc → HĐMB"},{"key":"Lưu ý","value":"Thời hạn DỰ ÁN 50 năm (QĐ 826) ≠ thời hạn sở hữu nhà ở của người mua"}]'::jsonb,'"Câu khách hỏi nhiều: ''dự án 50 năm thì sổ có 50 năm không?'' — Không. 50 năm là thời hạn giao dự án cho CĐT; người Việt mua nhà ở hình thành trong dự án vẫn được cấp sổ lâu dài."','✅ ĐÃ XÁC MINH về hình thức sổ lâu dài cho người Việt.',13),
  ('d433b0c8-0ad8-5adb-86ea-0f686c402ad0','00000000-0000-0000-0000-00000000b003','thap-108','Tháp 108 tầng','landmark','Chưa khởi công — biểu tượng truyền thông','[{"key":"Chiều cao (công bố)","value":"~550 m — \"vượt Landmark 81, top 10 thế giới\""},{"key":"Vị trí","value":"Phân khu C — Mũi Hải Đăng"},{"key":"Hiện trạng","value":"CHƯA khởi công; vị trí cách bờ hiện tại ~6 km, mặt bằng chưa hình thành"},{"key":"Định vị","value":"\"Ngọn hải đăng thế kỷ 21\""}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN — kế hoạch là thật (công bố CĐT), nhưng thông số và timeline chưa có văn bản/giấy phép xây dựng được công khai. Không dùng tháp 108 làm căn cứ định giá ngắn hạn.',14),
  ('804f0a1e-9e48-58a4-b8a3-640fdc4c7020','00000000-0000-0000-0000-00000000b003','lagoon','Paradise Lagoon (biển hồ nhân tạo)','landmark','⚠ Số liệu mâu thuẫn giữa các nguồn','[{"key":"Diện tích (các nguồn)","value":"443 ha / 757 ha / >800 ha — KHÔNG nhất quán"},{"key":"Loại","value":"Biển hồ nước mặn"},{"key":"Quảng bá","value":"\"Lớn nhất thế giới\""}]'::jsonb,null,'⚠ TIN ĐỒN / CHƯA XÁC MINH về thông số — con số chênh nhau gần gấp đôi tùy nguồn. Khi tư vấn chỉ nên nói "biển hồ nhân tạo quy mô hàng trăm ha", tránh chốt số.',15),
  ('12f5bfb5-3a81-533c-b930-2dc6d1c8bc23','00000000-0000-0000-0000-00000000b003','golf','2 sân golf 18 lỗ','landmark',null,'[{"key":"Số lượng","value":"2 sân × 18 lỗ — tại phân khu A"},{"key":"Quảng bá thiết kế","value":"Tiger Woods / Robert Trent Jones II"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN — quy hoạch sân golf có trong cơ cấu phân khu; tên nhà thiết kế là công bố truyền thông CĐT, chưa kiểm chứng hợp đồng.',16),
  ('78984ff3-a3a1-5303-84f5-485dc72f3dff','00000000-0000-0000-0000-00000000b003','tien-ich-lon','Cụm khách sạn & văn hóa','landmark',null,'[{"key":"Khách sạn","value":"~7.000 phòng — hợp tác Marriott (Ritz-Carlton + Marriott Hotel)"},{"key":"Nhà hát Sóng Xanh","value":"~5.000 chỗ (phân khu B)"},{"key":"Cảng du thuyền","value":"Landmark Harbour"},{"key":"Giải trí","value":"VinWonders 122 ha · Winter Wonderland"},{"key":"Y tế","value":"Vinmec"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN — chủ yếu công bố CĐT; hợp tác Marriott được truyền thông đưa tin nhưng chi tiết hợp đồng chưa công khai.',17),
  ('2873f1a4-0b61-5475-8410-2e208208943b','00000000-0000-0000-0000-00000000b003','cau-can-gio','Cầu Cần Giờ','infra',null,'[{"key":"Động thổ","value":"15/1/2026"},{"key":"Quy mô","value":"Dài ~6,3 km — 6 làn xe; cầu chính vượt sông Soài Rạp ~3 km"},{"key":"Vốn","value":">13.200 tỷ đồng (trước đó nêu ~11.087 tỷ)"},{"key":"Nhà đầu tư","value":"CTCP Masterise Hạ tầng Cần Giờ (Tập đoàn Masterise) — PPP, hợp đồng BT"},{"key":"Khởi công xây dựng","value":"Dự kiến 3/6/2026"},{"key":"Hợp long","value":"Cuối 2028"},{"key":"Khai thác","value":"Giữa 2029 — thay phà Bình Khánh"}]'::jsonb,'"20 năm Cần Giờ chỉ có MỘT con phà. Cây cầu đã động thổ với nhà đầu tư tên tuổi — và lịch sử BĐS Việt Nam chưa từng có khu vực nào KHÔNG tăng giá khi cây cầu đầu tiên nối nó với trung tâm thành hình."','✅ ĐÃ XÁC MINH (VnExpress, Tuổi Trẻ, Thanh Niên) Nút thắt lớn nhất của Cần Giờ suốt 20 năm. Mọi kịch bản giá khu vực đều neo vào mốc khai thác giữa 2029.',18),
  ('e64103d3-aafd-517b-bac0-0b9157ab5dd3','00000000-0000-0000-0000-00000000b003','metro-cg','Metro Bến Thành – Cần Giờ (350 km/h)','infra',null,'[{"key":"Pháp lý","value":"QĐ 3055/QĐ-UBND — 8/12/2025 (PCT Bùi Xuân Cường ký)"},{"key":"Chiều dài","value":"54,062 km — đường đôi khổ 1.435 mm"},{"key":"Tốc độ thiết kế","value":"350 km/h"},{"key":"Vốn sơ bộ","value":"~102.430 tỷ (chưa gồm ~12.784 tỷ GPMB do ngân sách)"},{"key":"Nhà đầu tư","value":"VinSpeed (Vingroup) — hợp đồng BOO"},{"key":"Động thổ","value":"19/12/2025"},{"key":"Vận hành","value":"Dự kiến 2028 — điểm cuối sát KĐT"},{"key":"Thời gian di chuyển","value":"~20 phút (CĐT marketing 12–13 phút)"}]'::jsonb,'"Điểm cần trung thực với khách: metro đã động thổ thật và có quyết định pháp lý thật — nhưng 54 km vận hành trong ~3 năm là tốc độ chưa có tiền lệ ở Việt Nam. Bán câu chuyện metro cho tầm nhìn 2030, đừng bán cho 2028."','✅ ĐÃ XÁC MINH về pháp lý/động thổ; mốc vận hành 2028 là mục tiêu rất tham vọng cho 54 km đường sắt tốc độ cao.',19),
  ('b189dfe2-f1ed-54b2-9672-d5dda2d28af1','00000000-0000-0000-0000-00000000b003','cang-tc','Cảng trung chuyển quốc tế Cần Giờ','infra',null,'[{"key":"Pháp lý","value":"QĐ 148/QĐ-TTg — 16/1/2025"},{"key":"Quy mô","value":"571 ha"},{"key":"Vốn","value":"~4,99 tỷ USD (>50.000 tỷ)"},{"key":"Liên danh","value":"VIMC 36% + Cảng Sài Gòn 15% + TIL/MSC 49% (hãng tàu container số 1 thế giới)"},{"key":"Động thổ","value":"Dự kiến 2026"},{"key":"Khai thác GĐ1","value":"Trước 2030"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Catalyst kinh tế bị đánh giá thấp nhất: cảng tạo việc làm + chuyên gia + logistics — tức cầu thuê thật cho Cần Giờ, thứ mọi thị trường nghỉ dưỡng thuần (như Hồ Tràm) không có.',20),
  ('4de3aed9-68c2-52a2-8684-554fb786a36c','00000000-0000-0000-0000-00000000b003','rung-sac','Đường Rừng Sác mở rộng','infra',null,'[{"key":"Kế hoạch","value":"Mở rộng 6–10 làn"},{"key":"Hiện trạng","value":"CTC được giao nghiên cứu — chưa chốt phương án/vốn"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN Trục độc đạo xuyên Cần Giờ hiện hữu — mở rộng là điều kiện cần để hấp thụ lưu lượng khi cầu Cần Giờ thông xe.',21),
  ('504bbd5a-b526-572b-83ea-e56654bd2712','00000000-0000-0000-0000-00000000b003','bl-lt','Cao tốc Bến Lức – Long Thành','infra',null,'[{"key":"Hoàn thành","value":"Dự kiến ~2026"},{"key":"Ý nghĩa với Cần Giờ","value":"Kết nối sân bay Long Thành + trục liên vùng phía Nam"}]'::jsonb,null,'✅ ĐÃ XÁC MINH',22),
  ('e5f74225-28d5-5e9c-9176-21535b6417f0','00000000-0000-0000-0000-00000000b003','pha-bien','Phà biển Cần Giờ – Vũng Tàu','infra',null,'[{"key":"Thời gian","value":"~30 phút"},{"key":"Hiện trạng","value":"Đang khai thác"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Kết nối hiện hữu duy nhất sang trục du lịch Vũng Tàu — nay cùng một TP.HCM sau sáp nhập.',23),
  ('87e17878-8fae-526b-8a3c-0d469e5c0ac2','00000000-0000-0000-0000-00000000b003','cau-vt','Cầu vượt biển CG – Vũng Tàu (đề xuất)','infra','⚠ Mới là đề xuất — chưa phê duyệt','[{"key":"Đề xuất","value":"Vingroup đề xuất nghiên cứu"},{"key":"Vốn ước","value":"~104.000 tỷ đồng"},{"key":"Trạng thái","value":"CHƯA có quyết định phê duyệt"}]'::jsonb,null,'⚠ TIN ĐỒN / CHƯA XÁC MINH ở cấp độ dự án — chỉ nên kể như tầm nhìn dài hạn, tuyệt đối không đưa vào căn cứ định giá.',24),
  ('ad93faa7-b5c7-50f0-8a89-e4724806bc9c','00000000-0000-0000-0000-00000000b003','sinh-quyen','Khu sinh quyển Cần Giờ (UNESCO)','env',null,'[{"key":"Công nhận","value":"UNESCO — năm 2000 (khu DTSQ đầu tiên của VN)"},{"key":"Quy mô","value":"~75.000 ha rừng ngập mặn — \"lá phổi xanh\" TP.HCM"},{"key":"Khoảng cách tới dự án","value":"Dự án cách VÙNG LÕI ~18 km"}]'::jsonb,null,'✅ ĐÃ XÁC MINH Bối cảnh khiến dự án này khác mọi dự án Vinhomes khác: nằm cạnh hệ sinh thái được bảo vệ quốc tế — câu hỏi môi trường là câu hỏi thường trực, không phải nhất thời.',25),
  ('61420c41-007a-5420-92b7-98e52ef249cc','00000000-0000-0000-0000-00000000b003','ung-ho','Luận điểm ủng hộ (chính thống)','env',null,'[{"key":"Bộ TN&MT (họp báo, Tuổi Trẻ 21/7/2020)","value":"Cách vùng lõi ~18 km — \"khoảng cách không ảnh hưởng\""},{"key":"Vụ trưởng Vụ Thẩm định ĐTM Nguyễn Xuân Hải","value":"Dự án \"chỉ tác động không đáng kể\""},{"key":"ĐTM","value":"Được phê duyệt 21/2/2025"},{"key":"Công nghệ CĐT","value":"Phun cát cân bằng đào–đắp (tham chiếu Palm Jumeirah, Dubai)"},{"key":"Cam kết","value":"Bảo hành nền móng trọn đời"}]'::jsonb,null,'✅ ĐÃ XÁC MINH về phát ngôn/văn bản — hiệu quả thực tế cần thời gian kiểm chứng.',26),
  ('2fc2c01c-eef2-5b3d-bd71-0ee2caf055b6','00000000-0000-0000-0000-00000000b003','phan-bien','Phản biện & lo ngại','env',null,'[{"key":"GS Lê Huy Bá (Người Đô Thị)","value":"Bờ kè đổi luồng chảy → giảm độ mặn; \"thay đổi 2% độ mặn là rừng ngập mặn sẽ chết\""},{"key":"ĐBQH Trương Trọng Nghĩa","value":"Chất vấn Quốc hội về tác động tới khu sinh quyển"},{"key":"Ban QL Rừng phòng hộ (6/2018)","value":"Cảnh báo ô nhiễm nguồn nước"},{"key":"Chính ĐTM","value":"Yêu cầu nghiên cứu TIẾP xói lở, bồi tụ, dòng chảy"}]'::jsonb,'"Đừng giấu node này với khách. Người mua 20–30 tỷ đều tự Google được — môi giới chủ động trình bày cả hai chiều sẽ thắng niềm tin so với người chỉ nói chiều thuận."','✅ ĐÃ XÁC MINH về việc các ý kiến này tồn tại (nguồn báo chí); tính đúng sai khoa học chưa ngã ngũ. Lưu ý: trên PLO, GS Bá có quan điểm ôn hòa hơn — bản thân giới chuyên gia không đồng nhất.',27),
  ('303dc03a-3edd-5e1f-a5ae-820d7d5ebc1a','00000000-0000-0000-0000-00000000b003','can-gio-area','Cần Giờ (khu vực)','location',null,'[{"key":"Hành chính từ 1/7/2025","value":"Bỏ cấp huyện — 6 xã + 1 thị trấn → 4 xã (NQ 1685/NQ-UBTVQH15)"},{"key":"Vị trí","value":"Cách trung tâm TP.HCM ~50 km — vùng biển duy nhất của TP"},{"key":"Kết nối hiện hữu","value":"Phà Bình Khánh + đường Rừng Sác + phà biển Vũng Tàu"}]'::jsonb,null,'✅ ĐÃ XÁC MINH',28),
  ('cdf3e7c8-3917-5afa-a028-0a944c7c1cd9','00000000-0000-0000-0000-00000000b003','xa-can-gio','Xã Cần Giờ (mới)','location',null,'[{"key":"Sáp nhập từ","value":"Xã Long Hòa + thị trấn Cần Thạnh"},{"key":"Vai trò","value":"Trung tâm — NƠI ĐẶT dự án Vinhomes Green Paradise"},{"key":"Giá đất tham chiếu","value":"Tắc Xuất/Cần Thạnh 45–80 · Long Hòa 20–60 tr/m²"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (NQ 1685) — giá là giá rao thị trường ◐ XÁC MINH MỘT PHẦN.',29),
  ('f3694619-056b-5020-b3b3-200765d26d62','00000000-0000-0000-0000-00000000b003','xa-binh-khanh','Xã Bình Khánh (mới)','location',null,'[{"key":"Sáp nhập từ","value":"Bình Khánh + Tam Thôn Hiệp + một phần An Thới Đông"},{"key":"Vai trò","value":"Cửa ngõ — vị trí phà hiện tại & chân cầu Cần Giờ"},{"key":"Giá tham chiếu","value":"Trục Rừng Sác 22–40; khu chân cầu 50–60 tr/m²"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (NQ 1685) Vùng hưởng lợi trực tiếp và sớm nhất từ cầu Cần Giờ — trước cả khu vực dự án.',30),
  ('73ad56b5-52d9-5dc6-877a-35d03dba4698','00000000-0000-0000-0000-00000000b003','xa-atd','Xã An Thới Đông (mới)','location',null,'[{"key":"Sáp nhập từ","value":"Lý Nhơn + phần còn lại An Thới Đông"},{"key":"Giá tham chiếu","value":"Lý Nhơn/Tam Thôn Hiệp 10–20 tr/m²"},{"key":"Đặc điểm","value":"Thuần nông — nhiều đất nuôi trồng thủy sản/rừng"}]'::jsonb,null,'✅ ĐÃ XÁC MINH (NQ 1685)',31),
  ('c4b8b926-74ff-5625-bade-3be79e11f214','00000000-0000-0000-0000-00000000b003','xa-thanh-an','Xã Thạnh An (xã đảo)','location',null,'[{"key":"Hiện trạng","value":"Giữ nguyên — xã đảo duy nhất của TP.HCM"},{"key":"Lưu ý đầu tư","value":"Hạn chế xây dựng/giao thông — không phải địa bàn đầu tư phổ thông"}]'::jsonb,null,'✅ ĐÃ XÁC MINH',32),
  ('19a19344-9eeb-51f7-bba2-dbc1d8519314','00000000-0000-0000-0000-00000000b003','royal-island','Vinhomes Royal Island (Vũ Yên, HP)','comparable',null,'[{"key":"Quy mô","value":"877 ha — mô hình \"thành phố đảo\""},{"key":"Giá tham chiếu (môi giới)","value":"Liền kề 9–20 tỷ · Biệt thự 16–50 tỷ"},{"key":"Điểm nhấn","value":"Biệt thự đảo có bãi tắm nước mặn sau nhà"},{"key":"Doanh số","value":"17% contracted sales VHM 9T2025"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN Mô hình tham chiếu gần nhất với Cần Giờ (đảo + mặt nước + lấn biển nhẹ) — và là bằng chứng Vinhomes bán được sản phẩm "thành phố đảo" với giá premium.',33),
  ('0baab984-6037-5f96-bbe9-6f9efd6b7c03','00000000-0000-0000-0000-00000000b003','ocean-park','Vinhomes Ocean Park (HN)','comparable',null,'[{"key":"Giá thấp tầng từng đạt","value":"~100–170 triệu/m² (LK/shophouse)"},{"key":"Cho thuê shophouse (môi giới dẫn)","value":"~300–400 triệu/năm"},{"key":"Q1/2026","value":"OCP 2&3 chiếm 70% doanh thu VHM"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN — số môi giới dẫn, chưa kiểm chứng độc lập. Là "bằng chứng giá" mà sale dùng để biện hộ mức rumor 99–134 tr/m² của Cần Giờ. Cần lưu ý khác biệt: OCP là đô thị ở thực sát Hà Nội, Cần Giờ là đô thị du lịch cách trung tâm 50 km.',34),
  ('e30d1ced-732d-5af2-b52d-a9e8a24972a4','00000000-0000-0000-0000-00000000b003','ho-tram','Hồ Tràm / Long Hải','comparable','Bài học rủi ro nghỉ dưỡng','[{"key":"Giá tham chiếu","value":"Condotel 1,5–6 tỷ · Biệt thự 4–60 tỷ"},{"key":"Tích cực","value":"The Grand Ho Tram mở rộng +1 tỷ USD (2025)"},{"key":"Tiêu cực","value":"Hàng nghìn BT/căn hộ dang dở, bỏ hoang (Dân trí 9/2024; Charm Resort…)"},{"key":"Hành chính","value":"Sau sáp nhập 1/7/2025 cùng thuộc TP.HCM"}]'::jsonb,null,'✅ ĐÃ XÁC MINH về hiện trạng dang dở (Dân trí ghi nhận thực địa). Lời cảnh tỉnh quan trọng nhất cho người mua Cần Giờ: BĐS nghỉ dưỡng biển từng vỡ thanh khoản ngay cạnh TP.HCM. Khác biệt của Cần Giờ phải đến từ: cầu + metro + cảng + dân số đô thị 230.000 — không phải từ "view biển".',35),
  ('7b0c18f7-e04a-5e02-a1a0-5a77a4556582','00000000-0000-0000-0000-00000000b003','doanh-so','Doanh số VGP (KQKD Vinhomes)','market',null,'[{"key":"9T2025 — contracted sales VHM","value":"162.600 tỷ đồng"},{"key":"Riêng Cần Giờ","value":"~65.000 tỷ — chiếm 40%, LỚN NHẤT hệ thống"},{"key":"Các dự án khác","value":"Wonder City 23% · Royal Island 17% · Green City 9%"},{"key":"Q1/2026 (BSC/Elibook 23/5/2026)","value":"DT VHM ~65.100 tỷ (+315% YoY); \"doanh thu còn lại chủ yếu từ Cần Giờ\""},{"key":"⚠ Không công bố","value":"Số booking / tỷ lệ hấp thụ riêng từng phân khu"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN (24HMoney/CafeF dẫn báo cáo Vinhomes; BSC) Bằng chứng thanh khoản mạnh nhất hiện có: dù chưa công bố giá qua báo chí, dự án đã là máy bán hàng số 1 của Vinhomes. Nhưng nhớ: contracted sales ≠ tỷ lệ hấp thụ — không suy ra "cháy hàng" từng phân khu.',36),
  ('ce3dc772-97ff-5f39-830d-ac67807b293c','00000000-0000-0000-0000-00000000b003','lich-su-gia','Lịch sử giá đất Cần Giờ','market',null,'[{"key":"Sốt 2017–2018","value":"+200% theo tin cầu Cần Giờ"},{"key":"Đỉnh 2020–2021","value":"Đất có quy hoạch chạm ~80 tr/m²"},{"key":"Điều chỉnh 2022–2024","value":"Giảm 10–30% từ đỉnh"},{"key":"Từ 10/2024","value":"Sôi động trở lại theo tin Vingroup khởi công — gần dự án/biển tăng 10–60%"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN (tổng hợp môi giới/Savills/Dân trí) Cần Giờ đã có ÍT NHẤT 2 chu kỳ sốt–xẹp theo tin hạ tầng. Người vào 2025–2026 đang mua ở chu kỳ thứ 3 — khác biệt lần này: hạ tầng đã động thổ thật thay vì chỉ là tin.',37),
  ('5bad6c00-1018-5109-a1d6-3fb3fdfde978','00000000-0000-0000-0000-00000000b003','gia-hien-tai','Giá đất hiện tại theo trục','market',null,'[{"key":"Trục Rừng Sác","value":"22–40 tr/m² (chân cầu 50–60)"},{"key":"Đường Thạnh Thới (cổng dự án)","value":"35–80; lô view biển/liền kề dự án >90"},{"key":"Tắc Xuất / trung tâm Cần Thạnh","value":"45–80 tr/m²"},{"key":"Long Hòa","value":"20–60 tr/m²"},{"key":"Lý Nhơn / Tam Thôn Hiệp","value":"10–20 tr/m²"},{"key":"Đất nông nghiệp / rừng","value":"1–1,9 tr/m²"},{"key":"Bảng giá nhà nước","value":"Cao nhất ~18,8 tr/m² (QĐ 02/2020, sửa đổi QĐ 79/2024)"}]'::jsonb,null,'◐ XÁC MINH MỘT PHẦN — giá RAO, biến động nhanh theo tin; bắt buộc khảo sát thực địa từng lô. Chênh lệch giá rao vs giá nhà nước (80 vs 18,8) cho thấy mức kỳ vọng đã nạp vào thị trường.',38),
  ('50f062e2-907f-5c6b-9970-6f5ac9066305','00000000-0000-0000-0000-00000000b003','rui-ro-datnen','Rủi ro đất nền ngoài dự án','market','⚠ Vùng cảnh báo của chuyên gia','[{"key":"Quỹ đất ở","value":"RẤT ít — chủ yếu đất nông nghiệp/thủy sản/rừng"},{"key":"Chuyển đổi","value":"Đất rừng/nuôi trồng KHÔNG chuyển đổi được"},{"key":"Quy hoạch","value":"Nhiều khu chức năng hỗn hợp — dễ mua nhầm đất dính quy hoạch"},{"key":"Cảnh báo","value":"Savills + ông Tạ Trung Kiên (Wowhome): lướt sóng theo tin dễ \"vỡ mộng\""},{"key":"Hành động bắt buộc","value":"Kiểm tra quy hoạch tại UBND xã trước khi cọc"}]'::jsonb,null,'✅ ĐÃ XÁC MINH về các cảnh báo (nguồn báo chí dẫn chuyên gia) Nghịch lý Cần Giờ: vùng sinh quyển phải bảo vệ nghiêm ngặt → đất ở hợp pháp khan hiếm → vừa là rủi ro (mua nhầm), vừa là luận điểm khan hiếm cho sản phẩm trong dự án có pháp lý sạch.',39),
  ('154ca00a-00c4-5902-a123-bfcfd575a7f3','00000000-0000-0000-0000-00000000b003','catalyst','Động lực tăng giá (catalyst)','broker',null,'[{"key":"1. Hạ tầng đã động thổ thật","value":"Cầu (15/1/2026) · Metro (19/12/2025) · Cảng (QĐ 148, động thổ dự kiến 2026)"},{"key":"2. Khan hiếm tuyệt đối","value":"Quỹ đất biển duy nhất của TP.HCM"},{"key":"3. Năng lực CĐT","value":"Vingroup + bảo hành nền móng trọn đời"},{"key":"4. Bằng chứng cầu thật","value":"Doanh số ~65.000 tỷ/9T2025"},{"key":"5. Biểu tượng","value":"Tháp 108 tầng + lagoon + 7.000 phòng khách sạn"}]'::jsonb,null,'Xếp theo độ chắc chắn giảm dần: 1–2 là sự thật đã diễn ra; 3–4 đã kiểm chứng; 5 là kỳ vọng truyền thông.',40),
  ('86015ed4-5a14-5684-9ac0-d87faf2d4d6f','00000000-0000-0000-0000-00000000b003','rui-ro-vgp','Bản đồ rủi ro','broker','⚠ Đọc trước khi tư vấn xuống tiền','[{"key":"1. Giá","value":"Rumor 99–134 tr/m² cao vượt xa mặt bằng vùng → biên tăng ngắn hạn hẹp"},{"key":"2. Tiến độ hạ tầng","value":"Metro 54 km vận hành 2028 là mốc chưa có tiền lệ; cầu 2029 là \"dự kiến\""},{"key":"3. Môi trường — pháp lý","value":"ĐTM kèm yêu cầu nghiên cứu tiếp; phản biện xã hội còn"},{"key":"4. Thanh khoản nghỉ dưỡng","value":"Bài học Hồ Tràm ngay bên cạnh"},{"key":"5. Cam kết thuê 6%/5 năm","value":"Chưa kiểm chứng độc lập — từ môi giới"}]'::jsonb,null,'Rủi ro lõi không phải dự án "ảo" (pháp lý và thi công rất thật) mà là trả giá của 2030 cho tài sản 2026 trong khi các mốc hạ tầng đều mang chữ "dự kiến".',41),
  ('f65b2ccb-0f65-56eb-9f25-87986cda25cd','00000000-0000-0000-0000-00000000b003','khach-mt','Khách hàng mục tiêu','broker',null,'[{"key":"Second home","value":"Giới thượng lưu TP.HCM — biển gần nhất có thương hiệu Vin"},{"key":"Đầu tư trung–dài hạn","value":"Tầm nhìn 3–5 năm gắn mốc cầu/metro"},{"key":"Khai thác dòng tiền","value":"Airbnb · shophouse F&B · cho chuyên gia cảng thuê"},{"key":"⚠ Yield","value":"CHƯA có dữ liệu xác thực — mọi con số là dẫn chiếu Ocean Park từ môi giới"}]'::jsonb,null,'Tệp KHÔNG phù hợp: nhà đầu tư đòn bẩy cao kỳ vọng lướt sóng 6–12 tháng — sản phẩm giá trị lớn, thanh khoản thứ cấp chưa hình thành.',42),
  ('9eee1494-2e07-52fa-a22d-b53a06c1f0bb','00000000-0000-0000-0000-00000000b003','phan-doi-qa','Phản đối thường gặp → trả lời','broker',null,'[{"key":"\"Lấn biển hại môi trường?\"","value":"ĐTM duyệt 21/2/2025 + cách lõi sinh quyển 18 km; trung thực: còn phản biện & yêu cầu giám sát tiếp"},{"key":"\"Bao giờ có cầu?\"","value":"Động thổ 15/1/2026 — khai thác DỰ KIẾN giữa 2029; metro động thổ 19/12/2025, dự kiến 2028"},{"key":"\"Giá quá cao so với Cần Giờ?\"","value":"So với đại đô thị tích hợp (OCP, Royal Island), không so đất nền nông nghiệp; quỹ đất biển duy nhất TP.HCM"},{"key":"\"Sổ lâu dài hay 50 năm?\"","value":"Người Việt: sổ hồng LÂU DÀI; người nước ngoài: 50 năm; 50 năm là thời hạn dự án của CĐT"}]'::jsonb,null,'Nguyên tắc chung: trả lời bằng số quyết định + ngày tháng, không trả lời bằng tính từ. Mọi mốc tương lai luôn kèm chữ "dự kiến".',43),
  ('81159a22-5d05-5076-bf76-1e94e2fbcdba','00000000-0000-0000-0000-00000000b003','khuyen-nghi','Khuyến nghị & ngưỡng đảo chiều','broker',null,'[{"key":"Trước khi xuống tiền","value":"Chỉ tin giá tại sự kiện mở bán chính thức của Vinhomes; yêu cầu xem HĐMB"},{"key":"Khung đầu tư","value":"Tầm nhìn 3–5 năm; ưu tiên sản phẩm có dòng tiền thật (shophouse trục chính)"},{"key":"Ngưỡng 1","value":"Cầu/metro trễ >12 tháng so công bố → hạ kỳ vọng ngắn hạn"},{"key":"Ngưỡng 2","value":"ĐTM điều chỉnh bị siết / phát sinh vấn đề môi trường → tăng chiết khấu rủi ro"},{"key":"Ngưỡng 3","value":"Giá mở bán chính thức cao hơn >15% rumor → tính lại biên lợi nhuận"},{"key":"Đất ngoài dự án","value":"CHỈ thổ cư có sổ tại xã Cần Giờ / Bình Khánh; kiểm tra quy hoạch tại UBND xã"}]'::jsonb,null,'Bán bằng mốc, không bán bằng cảm xúc — cập nhật lại toàn bộ knowledge map khi bất kỳ ngưỡng nào kích hoạt.',44);
